def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        base_factor = np.exp(-item / (cap + 1))
        complexity = 1.0
        mod_factor = 0.0
        nuanced_penalty = 0.0
        dynamic_weight = 1.0
        cascade_effect = 1.0
        for x in range(1, 20):
            if x % 2 == 0 and x % 3 != 0:
                complexity *= 1 + 0.03 * (x / 5)
            elif x % 3 == 0:
                complexity *= 0.95 - 0.02 * (x / 7)
            elif x % 5 == 0:
                complexity *= 1.02 + 0.01 * (x / 4)
            scaled_ratio = item / (cap + x)
            if scaled_ratio < 0.5:
                mod_factor += (np.sin(x * scaled_ratio * np.pi) + x**0.5) * complexity
            else:
                mod_factor += (np.cos(x + scaled_ratio) * np.log1p(x)) / (x + 2) * complexity
            if (cap * x + int(item)) % 11 == 0:
                mod_factor *= 1.07
            elif (cap + x**2) % 9 == 0:
                mod_factor *= 0.93
            if x % 4 == 1:
                if cap % (x+3) == 0:
                    nuanced_penalty += np.tanh(x * scaled_ratio) * 0.4
                else:
                    nuanced_penalty -= np.arcsin(min(1, abs(np.sin(x*scaled_ratio)))) * 0.2
            if x == 10:
                for y in range(1, 7):
                    gap = cap - item * y * (y+1) / 2
                    if gap > 0:
                        if gap % (y + 2) == 0:
                            dynamic_weight += np.log1p(gap) / (y+1)
                        else:
                            dynamic_weight -= np.sqrt(abs(gap)) / (y+3)
                    else:
                        dynamic_weight -= abs(gap)**1.2 / (y+4)
            if scaled_ratio > 0.7 and x % 3 == 0:
                cascade_effect *= 1.12 + 0.015 * x
            elif scaled_ratio < 0.15 and x % 5 == 0:
                cascade_effect *= 0.85 - 0.02 * x
        total_score = mod_factor + nuanced_penalty * 0.9 + dynamic_weight * 0.7
        total_score *= cascade_effect * base_factor
        if total_score < 0:
            priorities[idx] = -total_score * (np.log1p(cap) + np.sqrt(item))
        else:
            if cap > item * 3:
                priorities[idx] = -total_score / (np.sqrt(cap)*1.1 + 2) * (1 + scaled_ratio)
            else:
                priorities[idx] = -total_score / (cap + 5) * np.exp(-scaled_ratio**2 * 1.5)
        if scaled_ratio > 0.9:
            priorities[idx] *= 1.2
        elif scaled_ratio < 0.1:
            priorities[idx] *= 0.65
        if cap % 3 == 0 and cap % 2 != 0:
            priorities[idx] *= 1.05
        else:
            priorities[idx] *= 0.97
        if int(item) % 2 == 0:
            priorities[idx] *= 1.03
        else:
            priorities[idx] *= 0.99
    return priorities
